const raw = Buffer.from($input.first().json.content, 'base64').toString('utf-8');
const lines = raw.split('\n');
const numbered = lines.map((l, i) => `${i + 1}: ${l}`).join('\n');
return [{ json: {
  originalLines: lines,
  numberedContent: numbered,
  sha: $input.first().json.sha,
  filePath: $input.first().json.path
}}];

const raw = $json.choices[0].message.content.trim();
let issues = [];
try {
  const cleaned = raw.replace(/^```json\n?/,'').replace(/\n?```$/,'');
  issues = JSON.parse(cleaned);
  if (!Array.isArray(issues)) issues = [];
} catch(e) { issues = []; }

const decode = $('Decode & Prepare Lines').first().json;
return [{ json: {
  issues,
  issueCount: issues.length,
  originalLines: decode.originalLines,
  sha: decode.sha,
  filePath: decode.filePath,
  numberedContent: decode.numberedContent
}}];

const raw = $json.choices[0].message.content.trim();
const decode = $('Decode & Prepare Lines').first().json;
const qaJson = $('Parse QA JSON').first().json;
const totalLines = decode.originalLines.length;
let patches = [];
try {
  const cleaned = raw.replace(/^```json\n?/,'').replace(/\n?```$/,'');
  patches = JSON.parse(cleaned);
  if (!Array.isArray(patches)) patches = [];
} catch(e) { patches = []; }

const validPatches = patches.filter(p => {
  const start = p.line_range?.[0] ?? p.line_number;
  const end   = p.line_range?.[1] ?? p.line_number;
  return Number.isInteger(start) && Number.isInteger(end)
    && start >= 1 && end <= totalLines && start <= end
    && ['replace','insert_after','delete'].includes(p.operation);
});

validPatches.sort((a, b) => {
  const aStart = a.line_range?.[0] ?? a.line_number;
  const bStart = b.line_range?.[0] ?? b.line_number;
  return bStart - aStart;
});

return [{ json: {
  validPatches,
  skippedCount: patches.length - validPatches.length,
  originalLines: decode.originalLines,
  issues: qaJson.issues,
  sha: decode.sha,
  filePath: decode.filePath,
  numberedContent: decode.numberedContent
}}];

const lines = [...$input.first().json.originalLines];
for (const patch of $input.first().json.validPatches) {
  const start = (patch.line_range?.[0] ?? patch.line_number) - 1;
  const end   = (patch.line_range?.[1] ?? patch.line_number) - 1;
  if (patch.operation === 'replace') {
    lines.splice(start, end - start + 1, ...(patch.new_text ?? '').split('\n'));
  } else if (patch.operation === 'insert_after') {
    lines.splice(end + 1, 0, ...(patch.new_text ?? '').split('\n'));
  } else if (patch.operation === 'delete') {
    lines.splice(start, end - start + 1);
  }
}
const updatedContent = lines.join('\n');
return [{ json: {
  updatedContent,
  updatedContentB64: Buffer.from(updatedContent).toString('base64'),
  issues: $input.first().json.issues,
  validPatches: $input.first().json.validPatches,
  skippedCount: $input.first().json.skippedCount,
  sha: $input.first().json.sha,
  filePath: $input.first().json.filePath
}}];

const applyNode = $('Apply Patches').first().json;
const reportObj = {
  timestamp: new Date().toISOString(),
  issueCount: applyNode.issues.length,
  issues: applyNode.issues,
  patchesApplied: applyNode.validPatches.length,
  patchesSkipped: applyNode.skippedCount,
  patches: applyNode.validPatches
};
const content = Buffer.from(JSON.stringify(reportObj, null, 2)).toString('base64');
const qaReportSha = $input.first().json.sha ?? null;
const body = {
  message: 'QA report: ' + applyNode.issues.length + ' issues found',
  content,
  branch: 'main'
};
if (qaReportSha) body.sha = qaReportSha;
return [{ json: { qaReportBody: JSON.stringify(body) } }];
